/* N'o tЙ›, n'o tЙ›, ni fili dЙ” y'a sЙ”rЙ” a ma se ka sЙ”rЙ” (misali: a ma se ka sЙ”rЙ”, a ma se ka sЙ”rЙ”, a ma se ka sЙ”rЙ”, a tЙ› se ka a bЙ›Й› labЙ”), a bЙ› segin ka na ni fili dЙ” ye. A jirala cogo min na, a bЙ› segin ka na ni fili dЙ” ye. bool extract_archive archive *src, const char *dest_path) {structure archive *out; structure_entry *entry *entry; intrive flags = ARCHIVE_src_EXTRACT_TIME ARCHIVE_TRACT_PERM; intarch  */// Aw bЙ› sЙ›bЙ›nni sЙ›bЙ›nni kЙ›li daminЙ›    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);
// Aw bЙ› sЙ›bЙ›n kelen kelen bЙ›Й› kalan ka bЙ” a kЙ”nЙ”    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // Ka sira dafalen dilan        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);
// Aw bЙ› kunkan sЙ›bЙ›n        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }
// Kunnafoniw        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


